// Fetch IPMA stations to assign the nearest weather station to each beach.
// The 37 stations are district capitals — stable data that rarely changes.
const ipmaRes = await fetch('https://api.ipma.pt/open-data/distrits-islands.json');
const ipmaStations = await ipmaRes.json();

const features = $input.first().json.features ?? [];

function haversine(lat1, lon1, lat2, lon2) {
  const R = 6371;
  const dLat = (lat2 - lat1) * Math.PI / 180;
  const dLon = (lon2 - lon1) * Math.PI / 180;
  const a = Math.sin(dLat/2)**2 + Math.cos(lat1*Math.PI/180)*Math.cos(lat2*Math.PI/180)*Math.sin(dLon/2)**2;
  return R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a));
}

function nearestStation(lat, lon) {
  let best = null, bestDist = Infinity;
  for (const s of ipmaStations) {
    const d = haversine(lat, lon, parseFloat(s.latitude), parseFloat(s.longitude));
    if (d < bestDist) { bestDist = d; best = s; }
  }
  return best?.globalIdLocal ?? null;
}

// categoria_agua_balnear: 1 = costeira, 2 = fluvial, 3 = albufeira
function mapTipo(cat) {
  if (cat === 1) return 'costeira';
  if (cat === 2) return 'fluvial';
  if (cat === 3) return 'albufeira';
  return null;
}

return features.map(f => {
  const a = f.attributes;
  const lat = f.geometry?.y ?? null;
  const lng = f.geometry?.x ?? null;
  return {
    json: {
      nome: a.nome_praia ?? 'Sem nome',
      concelho: a.concelho ?? null,
      distrito: null,
      latitude: lat,
      longitude: lng,
      tipo: mapTipo(a.categoria_agua_balnear),
      bandeira_azul: a.bandeira_azul === 1,
      nadador_salvador: a.vigilancia === 1,
      acessivel: a.acessivel === 1,
      restaurante: a.apoio_balnear === 1,
      estacionamento: a.estacionamento === 1 ? null : 'inexistente',
      estacionamento_capacidade: null,
      estacionamento_distancia_metros: null,
      descricao: null,
      ipma_global_id: (lat && lng) ? nearestStation(lat, lng) : null,
    }
  };
});
